Here's how to write proper MSTest tests for `DataFetcher` with timeout and cancellation handling:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static HttpClient CreateClientWithHandler(HttpMessageHandler handler) => new(handler);

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        using var client = CreateClientWithHandler(handler);
        var fetcher = new DataFetcher(client);

        // Act — pass CancellationToken so [Timeout] can cancel cooperatively
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.InternalServerError));
        using var client = CreateClientWithHandler(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — a handler that delays long enough for cancellation to fire
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(30));
        using var client = CreateClientWithHandler(handler);
        var fetcher = new DataFetcher(client);

        // Cancel immediately
        cts.Cancel();

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_SlowServer_CancelledByTimeout()
    {
        // Arrange — handler that never completes within the timeout
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(60));
        using var client = CreateClientWithHandler(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert — [Timeout] triggers CancellationToken after 3s
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    /// <summary>Minimal fake handler — no mocking framework needed.</summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage? _response;
        private readonly TimeSpan _delay;

        public FakeHandler(HttpResponseMessage response) => _response = response;

        public FakeHandler(TimeSpan delay) => _delay = delay;

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken); // throws if cancelled
            }

            return _response ?? new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `[Timeout] + _testContext.CancellationToken` | Cooperative cancellation — the token fires when the timeout elapses |
| `Assert.ThrowsExactlyAsync<T>` | Catches the exact exception type, no `[ExpectedException]` needed |
| `FakeHandler` | Avoids mocking frameworks; gives full control over delay/response |
| Sealed test class + sealed handler | Performance and design clarity |

The critical insight: **`[Timeout]` only works if you pass `TestContext.CancellationToken`** into the async call chain. Without it, the test hangs until the framework force-kills the thread.
